import{_ as a,c as s,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Registro de Cambios: Historial de Versiones | OpenSkills","description":"Consulta el historial de versiones de OpenSkills. Conoce las nuevas funciones, mejoras y correcciones de cada versión para ayudarte a planificar tu ruta de actualización.","frontmatter":{"title":"Registro de Cambios: Historial de Versiones | OpenSkills","sidebarTitle":"Conoce los Últimos Cambios","subtitle":"Registro de Cambios: Historial de Versiones","description":"Consulta el historial de versiones de OpenSkills. Conoce las nuevas funciones, mejoras y correcciones de cada versión para ayudarte a planificar tu ruta de actualización.","order":6},"headers":[],"relativePath":"es/numman-ali/openskills/changelog/index.md","filePath":"es/numman-ali/openskills/changelog/index.md"}'),r={name:"es/numman-ali/openskills/changelog/index.md"};function n(t,e,l,d,c,u){return i(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="registro-de-cambios" tabindex="-1">Registro de Cambios <a class="header-anchor" href="#registro-de-cambios" aria-label="Permalink to &quot;Registro de Cambios&quot;">​</a></h1><p>Esta sección documenta el historial de versiones de OpenSkills, ayudándote a comprender las nuevas funciones, mejoras y correcciones de errores en cada versión.</p><h2 id="contenido-de-este-capitulo" tabindex="-1">Contenido de este Capítulo <a class="header-anchor" href="#contenido-de-este-capitulo" aria-label="Permalink to &quot;Contenido de este Capítulo&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Página</th><th>Descripción</th></tr></thead><tbody><tr><td><a href="./changelog/">Registro de Cambios</a></td><td>Registro completo de cambios de versión, incluyendo nuevas funciones, mejoras, correcciones de errores y actualizaciones de seguridad</td></tr></tbody></table><h2 id="como-usar-el-registro-de-cambios" tabindex="-1">Cómo Usar el Registro de Cambios <a class="header-anchor" href="#como-usar-el-registro-de-cambios" aria-label="Permalink to &quot;Cómo Usar el Registro de Cambios&quot;">​</a></h2><p>El registro de cambios está ordenado por número de versión en orden descendente (la versión más reciente primero). Cada versión incluye las siguientes categorías:</p><ul><li><strong>Nuevas Funciones</strong> - Funcionalidades y comandos recién añadidos</li><li><strong>Mejoras</strong> - Optimizaciones y mejoras de funcionalidades existentes</li><li><strong>Correcciones de Errores</strong> - Bugs que han sido solucionados</li><li><strong>Seguridad</strong> - Mejoras relacionadas con la seguridad</li></ul><div class="tip custom-block"><p class="custom-block-title">Recomendación de Actualización</p><p>Antes de actualizar OpenSkills, se recomienda revisar el registro de cambios para comprender las modificaciones de la versión, prestando especial atención a:</p><ul><li><strong>Breaking Changes</strong> (Cambios Rupturistas)</li><li>Cómo utilizar las nuevas funciones</li><li>El estado de corrección de problemas conocidos</li></ul></div><h2 id="siguientes-pasos" tabindex="-1">Siguientes Pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes Pasos&quot;">​</a></h2><ul><li>Consulta las <a href="./../faq/faq/">Preguntas Frecuentes</a> para resolver dudas comunes de uso</li><li>¿Tienes problemas? Revisa la <a href="./../faq/troubleshooting/">Solución de Problemas</a> para obtener soluciones</li><li>¿Quieres saber más? Consulta la <a href="./../appendix/cli-api/">Referencia de API CLI</a> para la documentación completa de comandos</li></ul>',10)])])}const g=a(r,[["render",n]]);export{p as __pageData,g as default};
